];

% 提取数据列
X = data(:, 1);       % X 坐标
Y = data(:, 2);       % Y 坐标
Z = data(:, 3);       % Z 坐标
ReEx = data(:, 4);    % Ex 实部
ImEx = data(:, 5);    % Ex 虚部

% 选择 Y = 10 的数据
selected_data = data(Y == 1.00000000E+01, :);

% 提取 X, Z 和 Ex 的实部与虚部
X_selected = selected_data(:, 1);
Z_selected = selected_data(:, 3);
ReEx_selected = selected_data(:, 4);
ImEx_selected = selected_data(:, 5);

% 计算 Ex 的幅值
Ex_magnitude_selected = sqrt(ReEx_selected.^2 + ImEx_selected.^2);

% 创建加密网格进行插值（提高场强均匀性）
nPtsX = 200;  % X 方向插值点数
nPtsZ = 200;  % Z 方向插值点数
xFine = linspace(min(X_selected), max(X_selected), nPtsX);
zFine = linspace(min(Z_selected), max(Z_selected), nPtsZ);
[Xgrid, Zgrid] = meshgrid(xFine, zFine);

% 使用 griddata 插值 Ex 幅值到加密网格上
Ex_grid = griddata(X_selected, Z_selected, Ex_magnitude_selected, Xgrid, Zgrid, 'cubic');

% 高斯平滑，进一步提升场强均匀性（sigma 可调）
smoothSigma = 80;
Ex_grid = imgaussfilt(Ex_grid, smoothSigma);

% 绘制 X-Z 平面图
figure;
pcolor(Xgrid, Zgrid, Ex_grid); % 用颜色表示幅值
shading interp;                % 平滑显示
xlabel('X(m)', 'FontSize', 24);
ylabel('Z(m)', 'FontSize', 24);
title('|Ex| [V/m] 125MHz', 'FontSize', 24);
colorbar;                      % 添加颜色条
set(gca, 'FontSize', 35);      % 设置坐标轴刻度字体大小

% 使用默认颜色映射 (jet)
colormap jet;                  % 恢复默认 jet 颜色映射
caxis([min(Ex_grid(:)) max(Ex_grid(:))]); % 设置颜色范围